import {
  FEATURE_REQUIREMENTS,
  PLAN_VIDEO_LIMITS,
  PLAN_STORAGE_LIMITS_GB,
  type PlanTier,
  type FeatureKey,
} from '@/lib/billing/feature-gate';

import { PLANS, PLAN_LIMITS_SUMMARY, isValidPlanTier } from '@/lib/billing/limits';

// ============================================================================
// Feature Requirements Tests
// ============================================================================

describe('Billing Infrastructure', () => {
  describe('Feature Requirements', () => {
    it('should define all expected features', () => {
      const expectedFeatures: FeatureKey[] = [
        'video_create',
        'video_hd',
        'video_4k',
        'avatar',
        'lip_sync',
        'tts_advanced',
        'white_label',
        'api_access',
        'multi_user',
        'scorm_export',
        'custom_branding',
        'priority_render',
        'unlimited_storage',
      ];

      for (const feature of expectedFeatures) {
        expect(FEATURE_REQUIREMENTS[feature]).toBeDefined();
        expect(Array.isArray(FEATURE_REQUIREMENTS[feature])).toBe(true);
        expect(FEATURE_REQUIREMENTS[feature].length).toBeGreaterThan(0);
      }
    });

    it('should allow video_create for all plans', () => {
      expect(FEATURE_REQUIREMENTS.video_create).toContain('free');
      expect(FEATURE_REQUIREMENTS.video_create).toContain('pro');
      expect(FEATURE_REQUIREMENTS.video_create).toContain('business');
    });

    it('should restrict premium features from free plan', () => {
      const premiumFeatures: FeatureKey[] = [
        'video_hd',
        'avatar',
        'lip_sync',
        'tts_advanced',
      ];

      for (const feature of premiumFeatures) {
        expect(FEATURE_REQUIREMENTS[feature]).not.toContain('free');
      }
    });

    it('should restrict business-only features', () => {
      const businessOnly: FeatureKey[] = [
        'video_4k',
        'white_label',
        'api_access',
        'multi_user',
        'custom_branding',
        'priority_render',
        'unlimited_storage',
      ];

      for (const feature of businessOnly) {
        expect(FEATURE_REQUIREMENTS[feature]).toContain('business');
        expect(FEATURE_REQUIREMENTS[feature]).not.toContain('free');
      }
    });
  });

  // ============================================================================
  // Plan Video Limits Tests
  // ============================================================================

  describe('Plan Video Limits', () => {
    it('should define limits for all plan tiers', () => {
      const tiers: PlanTier[] = ['free', 'pro', 'business'];
      for (const tier of tiers) {
        expect(PLAN_VIDEO_LIMITS[tier]).toBeDefined();
        expect(typeof PLAN_VIDEO_LIMITS[tier]).toBe('number');
      }
    });

    it('should have ascending limits from free to business', () => {
      expect(PLAN_VIDEO_LIMITS.free).toBeLessThan(PLAN_VIDEO_LIMITS.pro);
      expect(PLAN_VIDEO_LIMITS.pro).toBeLessThan(PLAN_VIDEO_LIMITS.business);
    });

    it('should have free plan with 1 video limit', () => {
      expect(PLAN_VIDEO_LIMITS.free).toBe(1);
    });

    it('should have pro plan with 10 video limit', () => {
      expect(PLAN_VIDEO_LIMITS.pro).toBe(10);
    });

    it('should have business plan with effectively unlimited videos', () => {
      expect(PLAN_VIDEO_LIMITS.business).toBeGreaterThanOrEqual(999);
    });
  });

  // ============================================================================
  // Plan Storage Limits Tests
  // ============================================================================

  describe('Plan Storage Limits', () => {
    it('should define storage limits for all tiers', () => {
      const tiers: PlanTier[] = ['free', 'pro', 'business'];
      for (const tier of tiers) {
        expect(PLAN_STORAGE_LIMITS_GB[tier]).toBeDefined();
        expect(typeof PLAN_STORAGE_LIMITS_GB[tier]).toBe('number');
      }
    });

    it('should have ascending storage from free to business', () => {
      expect(PLAN_STORAGE_LIMITS_GB.free).toBeLessThan(PLAN_STORAGE_LIMITS_GB.pro);
      expect(PLAN_STORAGE_LIMITS_GB.pro).toBeLessThan(PLAN_STORAGE_LIMITS_GB.business);
    });

    it('should have reasonable storage limits', () => {
      expect(PLAN_STORAGE_LIMITS_GB.free).toBeGreaterThanOrEqual(1);
      expect(PLAN_STORAGE_LIMITS_GB.pro).toBeGreaterThanOrEqual(10);
      expect(PLAN_STORAGE_LIMITS_GB.business).toBeGreaterThanOrEqual(50);
    });
  });

  // ============================================================================
  // PLANS Config (from limits.ts) Tests
  // ============================================================================

  describe('PLANS Configuration', () => {
    it('should define free, pro and business plans', () => {
      expect(PLANS.free).toBeDefined();
      expect(PLANS.pro).toBeDefined();
      expect(PLANS.business).toBeDefined();
    });

    it('should have correct names', () => {
      expect(PLANS.free.name).toBe('Free');
      expect(PLANS.pro.name).toBe('Pro');
      expect(PLANS.business.name).toBe('Business');
    });

    it('should have render limits', () => {
      expect(PLANS.free.limits.rendersPerMonth).toBe(5);
      expect(PLANS.pro.limits.rendersPerMonth).toBe(100);
      expect(PLANS.business.limits.rendersPerMonth).toBe(999999);
    });

    it('should have storage limits in bytes', () => {
      expect(PLANS.free.limits.storageBytes).toBe(1024 * 1024 * 1024 * 1); // 1GB
      expect(PLANS.pro.limits.storageBytes).toBe(1024 * 1024 * 1024 * 50); // 50GB
      expect(PLANS.business.limits.storageBytes).toBe(1024 * 1024 * 1024 * 200); // 200GB
    });

    it('should have video duration limits', () => {
      expect(PLANS.free.limits.maxVideoDurationSeconds).toBe(300); // 5 min
      expect(PLANS.pro.limits.maxVideoDurationSeconds).toBe(1800); // 30 min
      expect(PLANS.business.limits.maxVideoDurationSeconds).toBe(7200); // 2 hours
    });

    it('should have TTS limits', () => {
      expect(PLANS.free.limits.ttsMinutesPerMonth).toBe(5);
      expect(PLANS.pro.limits.ttsMinutesPerMonth).toBe(60);
      expect(PLANS.business.limits.ttsMinutesPerMonth).toBe(9999);
    });

    it('should have videos per month limits', () => {
      expect(PLANS.free.limits.videosPerMonth).toBe(1);
      expect(PLANS.pro.limits.videosPerMonth).toBe(10);
      expect(PLANS.business.limits.videosPerMonth).toBe(999999);
    });

    it('should have storage GB shortcut', () => {
      expect(PLANS.free.limits.storageGb).toBe(1);
      expect(PLANS.pro.limits.storageGb).toBe(50);
      expect(PLANS.business.limits.storageGb).toBe(200);
    });

    it('pro plan should have higher limits than free', () => {
      expect(PLANS.pro.limits.rendersPerMonth).toBeGreaterThan(PLANS.free.limits.rendersPerMonth);
      expect(PLANS.pro.limits.storageBytes).toBeGreaterThan(PLANS.free.limits.storageBytes);
      expect(PLANS.pro.limits.maxVideoDurationSeconds).toBeGreaterThan(PLANS.free.limits.maxVideoDurationSeconds);
    });

    it('business plan should have higher limits than pro', () => {
      expect(PLANS.business.limits.rendersPerMonth).toBeGreaterThan(PLANS.pro.limits.rendersPerMonth);
      expect(PLANS.business.limits.storageBytes).toBeGreaterThan(PLANS.pro.limits.storageBytes);
      expect(PLANS.business.limits.maxVideoDurationSeconds).toBeGreaterThan(PLANS.pro.limits.maxVideoDurationSeconds);
    });
  });

  // ============================================================================
  // Centralized Limits Consistency Tests
  // ============================================================================

  describe('Centralized Limits Consistency', () => {
    it('PLAN_VIDEO_LIMITS should match PLANS.limits.videosPerMonth', () => {
      const tiers: PlanTier[] = ['free', 'pro', 'business'];
      for (const tier of tiers) {
        expect(PLAN_VIDEO_LIMITS[tier]).toBe(PLANS[tier].limits.videosPerMonth);
      }
    });

    it('PLAN_STORAGE_LIMITS_GB should match PLANS.limits.storageGb', () => {
      const tiers: PlanTier[] = ['free', 'pro', 'business'];
      for (const tier of tiers) {
        expect(PLAN_STORAGE_LIMITS_GB[tier]).toBe(PLANS[tier].limits.storageGb);
      }
    });

    it('PLAN_LIMITS_SUMMARY should match PLANS values', () => {
      const tiers: PlanTier[] = ['free', 'pro', 'business'];
      for (const tier of tiers) {
        expect(PLAN_LIMITS_SUMMARY[tier].videos).toBe(PLANS[tier].limits.videosPerMonth);
        expect(PLAN_LIMITS_SUMMARY[tier].storage_gb).toBe(PLANS[tier].limits.storageGb);
        expect(PLAN_LIMITS_SUMMARY[tier].tts_minutes).toBe(PLANS[tier].limits.ttsMinutesPerMonth);
      }
    });

    it('isValidPlanTier should validate tiers correctly', () => {
      expect(isValidPlanTier('free')).toBe(true);
      expect(isValidPlanTier('pro')).toBe(true);
      expect(isValidPlanTier('business')).toBe(true);
      expect(isValidPlanTier('enterprise')).toBe(false);
      expect(isValidPlanTier('')).toBe(false);
      expect(isValidPlanTier('FREE')).toBe(false);
    });
  });

  // ============================================================================
  // Webhook Event Types Tests
  // ============================================================================

  describe('Stripe Webhook Event Handling', () => {
    const EXPECTED_EVENTS = [
      'checkout.session.completed',
      'customer.subscription.created',
      'customer.subscription.updated',
      'customer.subscription.deleted',
      'invoice.paid',
      'invoice.payment_failed',
    ];

    it('should define all critical webhook events', () => {
      // These events are handled in the webhook route handler
      for (const event of EXPECTED_EVENTS) {
        expect(typeof event).toBe('string');
        expect(event.length).toBeGreaterThan(0);
      }
    });

    it('should have matching number of expected events', () => {
      expect(EXPECTED_EVENTS).toHaveLength(6);
    });
  });

  // ============================================================================
  // Price-to-Plan Mapping Tests
  // ============================================================================

  describe('Price-to-Plan Mapping', () => {
    it('should map price IDs to correct plans', () => {
      // The webhook uses PRICE_TO_PLAN mapping
      // Validate the expected env var names
      const expectedEnvVars = [
        'STRIPE_PRICE_PRO_MONTHLY',
        'STRIPE_PRICE_PRO_YEARLY',
        'STRIPE_PRICE_BUSINESS_MONTHLY',
        'STRIPE_PRICE_BUSINESS_YEARLY',
      ];

      for (const envVar of expectedEnvVars) {
        expect(typeof envVar).toBe('string');
        if (envVar.includes('PRO')) {
          expect(envVar).toMatch(/PRO/);
        }
        if (envVar.includes('BUSINESS')) {
          expect(envVar).toMatch(/BUSINESS/);
        }
      }
    });

    it('should define plan limits for webhook handler', () => {
      const PLAN_LIMITS: Record<string, number> = {
        free: 1,
        pro: 10,
        business: -1, // unlimited
      };

      expect(PLAN_LIMITS.free).toBe(1);
      expect(PLAN_LIMITS.pro).toBe(10);
      expect(PLAN_LIMITS.business).toBe(-1);
    });
  });

  // ============================================================================
  // Checkout Configuration Tests
  // ============================================================================

  describe('Checkout Configuration', () => {
    it('should define price ID mappings for all plan types', () => {
      const PRICE_IDS = {
        pro_monthly: process.env.STRIPE_PRICE_PRO_MONTHLY || 'price_pro_monthly',
        pro_yearly: process.env.STRIPE_PRICE_PRO_YEARLY || 'price_pro_yearly',
        business_monthly: process.env.STRIPE_PRICE_BUSINESS_MONTHLY || 'price_business_monthly',
        business_yearly: process.env.STRIPE_PRICE_BUSINESS_YEARLY || 'price_business_yearly',
      };

      expect(Object.keys(PRICE_IDS)).toHaveLength(4);
      expect(PRICE_IDS.pro_monthly).toBeTruthy();
      expect(PRICE_IDS.pro_yearly).toBeTruthy();
      expect(PRICE_IDS.business_monthly).toBeTruthy();
      expect(PRICE_IDS.business_yearly).toBeTruthy();
    });

    it('should have valid priceId options for checkout', () => {
      const validPriceIds = ['pro_monthly', 'pro_yearly', 'business_monthly', 'business_yearly'];
      expect(validPriceIds).toHaveLength(4);
      
      for (const id of validPriceIds) {
        expect(id).toMatch(/^(pro|business)_(monthly|yearly)$/);
      }
    });
  });

  // ============================================================================
  // Credit Manager Tests
  // ============================================================================

  describe('Credit Manager', () => {
    it('should import CreditManager class', async () => {
      const { CreditManager } = await import('@/lib/billing/credit-manager');
      expect(CreditManager).toBeDefined();
      expect(typeof CreditManager).toBe('function');
    });

    it('should instantiate CreditManager', async () => {
      const { CreditManager } = await import('@/lib/billing/credit-manager');
      const manager = new CreditManager();
      expect(manager).toBeDefined();
      expect(typeof manager.hasCredits).toBe('function');
      expect(typeof manager.getBalance).toBe('function');
      expect(typeof manager.deductCredits).toBe('function');
      expect(typeof manager.refundCredits).toBe('function');
    });
  });
});
